import re
from jsonschema import validate, ValidationError

# 1. coincidencia exacta — clasificación, categorías cerradas
def grader_exact_match(obtenido, esperado):
    return obtenido.strip().lower() == esperado.strip().lower()

# 2. expresión regular — formato libre pero con un patrón obligatorio
def grader_regex(texto, patron=r"^\[(envio|reembolso|producto_defectuoso)\]"):
    return bool(re.match(patron, texto))

# 3. validación de schema — salidas estructuradas (JSON / tool use)
def grader_schema(datos_json, schema):
    try:
        validate(instance=datos_json, schema=schema)
        return True
    except ValidationError:
        return False

aciertos = sum(1 for r in resultados if grader_exact_match(r["obtenido"], r["esperado"]))
