import random

def muestreo_estratificado(extracciones: list[dict], min_por_estrato: int = 15) -> list[dict]:
    estratos: dict[tuple, list[dict]] = {}
    for ext in extracciones:
        clave = (ext["document_type"], ext["confidence_bucket"])  # ej: ("invoice", "low")
        estratos.setdefault(clave, []).append(ext)

    muestra = []
    for clave, items in estratos.items():
        n = min(min_por_estrato, len(items))
        muestra.extend(random.sample(items, n))
    return muestra  # cada estrato queda representado, sin importar su tamaño original

extraction_schema = {
    "type": "object",
    "properties": {
        "invoice_number": {"type": "string"},
        "invoice_number_confidence": {"type": "number", "minimum": 0, "maximum": 1},
        "total_amount": {"type": ["number", "null"]},
        "total_amount_confidence": {"type": "number", "minimum": 0, "maximum": 1},
        "due_date": {"type": ["string", "null"]},
        "due_date_confidence": {"type": "number", "minimum": 0, "maximum": 1},
    },
    "required": ["invoice_number", "invoice_number_confidence",
                 "total_amount_confidence", "due_date_confidence"],
}

