def calibrar_umbral(set_validacion: list[dict]) -> dict:
    # set_validacion: [{"confidence": 0.92, "correct": True}, ...] con ground truth humano
    buckets = {}
    for item in set_validacion:
        bucket = round(item["confidence"], 1)
        buckets.setdefault(bucket, []).append(item["correct"])

    calibracion = {
        bucket: sum(aciertos) / len(aciertos)
        for bucket, aciertos in buckets.items()
    }
    # si confidence=0.9 corresponde a accuracy real de 0.65, el modelo está
    # sobreconfiado en ese rango: el umbral de auto-aprobación debe subir
    return calibracion
